---解析不能直接使用的挂机数据
function LFightIdleManager:ParseIdleConfig()
	if self._bParseConfig then return end
	self._bParseConfig = true

	-----------------------------------------------------------------
	--头顶光效
	self._cfgHeadEffectName = GameTable.MainInstanceConfigRef["HeroOnHookLabel"]


	local arrHeroHitMon = LxDataHelper.Parse_IntK_ListIntV_Semicolon(GameTable.MainInstanceConfigRef["HeroHitMon"] or "")
	local heroHitMonMap = {}
	for k,v in pairs(arrHeroHitMon) do
		heroHitMonMap[k] = {min = v[1], max = v[2]}
	end
	self._cfgVHeroHitMonMap = heroHitMonMap

	self._cfgVMonAttPerMap = LxDataHelper.ParseIntKVList_Semicolon(GameTable.MainInstanceConfigRef["MonAttPer"] or "")

	-----------------------------------------------------------------
	local monBoardNum,monBoardUnit = LxDataHelper.ParseIntKV_Equal(GameTable.MainInstanceConfigRef["MonBoardNum"] or "")
	self._cfgVBoardNum = {num = monBoardNum or 1, unit = monBoardUnit or 1}

	self._cfgVMonWeightList = LxDataHelper.ParseIntKVList_Semicolon(GameTable.MainInstanceConfigRef["MonQualityWeight"]  or "")
	self._cfgVMonQualityMaxList = LxDataHelper.ParseIntKVList_Semicolon(GameTable.MainInstanceConfigRef["MonQualityMax"]  or "")
	self._cfgVMonWeightAddList = LxDataHelper.ParseIntKVList_Semicolon(GameTable.MainInstanceConfigRef["MonQualityWeightAdd"]  or "")
	-----------------------------------------------------------------
	self._cfgVHeroAttDisOnHookMap = LxDataHelper.ParseIntKVList_Semicolon(GameTable.MainInstanceConfigRef["HeroAttDisOnHook"] or "")

	local arrMonAttDisOnHook = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["MonAttDisOnHook"] or "")
	self._cfgVMonAttDisOnHookTbl = {min=tonumber(arrMonAttDisOnHook[1]) or 0 , max = tonumber(arrMonAttDisOnHook[2]) or 0}

	local arrMonMoveArea = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["MonMoveArea"] or "")
	self._cfgVMonMoveAreaSize = {min=tonumber(arrMonMoveArea[1]) or 0, max = tonumber(arrMonMoveArea[2]) or 0}


	local arrMonStayTime = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["MonStayTime"] or "")
	self._cfgVMonStayTimeLimit = {min=tonumber(arrMonStayTime[1]) or 0, max = tonumber(arrMonStayTime[2]) or 0}

	self._cfgVMonSizeOnHook = LxDataHelper.ParseIntKVList_Semicolon(GameTable.MainInstanceConfigRef["MonSizeOnHook"] or "")

	-----------------------------------------------------------------
	--飘字伤害分隔
	local floatHurtMinMap = LxDataHelper.Parse_IntK_ListIntV_Semicolon(GameTable.MainInstanceConfigRef["FloatHurtMin"] or {}) -- [[100=2:3;1000=3:5;10000=6:8]]
	local floatHurtSplitList = {}
	for k,v in pairs(floatHurtMinMap) do
		local minHurt = k
		local minCount = v[1] or 0
		local maxCount = v[2] or 0
		table.insert(floatHurtSplitList,{limitVal=minHurt,min=minCount,max=maxCount})
	end
	table.sort(floatHurtSplitList,function (fa,fb) return fa.limitVal < fb.limitVal end)
	self._cfgVFloatHurtSplitList = floatHurtSplitList

	local arrFloatHurtWave = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["FloatHurtWave"] or "")-- [[0.9;1.1]]
	self._cfgVFloatHurtWaveMin = tonumber(arrFloatHurtWave[1]) or 0
	self._cfgVFloatHurtWaveMax = tonumber(arrFloatHurtWave[2]) or 0

	local arrFloatHurtXStr = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["FloatHurtX"] or "")-- [[0.9;1.1]]
	self._cfgVHurtXMin = tonumber(arrFloatHurtXStr[1]) or 0
	self._cfgVHurtXMax = tonumber(arrFloatHurtXStr[2]) or 0

	-----------------------------------------------------------------
	-- local arrTalkTime = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["InstanceTalkTime"] or "")-- [[0.9;1.1]]
	-- self._cfgVTalkTimeMin = tonumber(arrTalkTime[1]) or 60
	-- self._cfgVTalkTimeMax = tonumber(arrTalkTime[2]) or 100
	self._cfgVTalkTimeMin = 60
	self._cfgVTalkTimeMax = 100

	-- local arrMonTalkTime = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["MonsterTalkTime"] or "")-- [[0.9;1.1]]
	-- self._cfgVMonTalkTimeMin = tonumber(arrMonTalkTime[1]) or 60
	-- self._cfgVMonTalkTimeMax = tonumber(arrMonTalkTime[1]) or 100
	self._cfgVMonTalkTimeMin = 60
	self._cfgVMonTalkTimeMax = 100

	-----------------------------------------------------------------
	local arrCameraMoveXYStr = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["CameraMoveXY"] or "")-- [[0.9;1.1]]
	local cameraMoveX = tonumber(arrCameraMoveXYStr[1]) or 0
	local cameraMoveY = tonumber(arrCameraMoveXYStr[2]) or 0
	self._cfgVCameraFollowOffset = Vector3(cameraMoveX * 0.01,cameraMoveY * 0.01,0)
	self._cfgVCameraFollowRange = (GameTable.MainInstanceConfigRef["CameraMoveR"] or 0) * 0.01

	-----------------------------------------------------------------
	local arrTimeShowDis = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["TimeShowDis"] or "")-- [[0.9;1.1]]
	self._cfgVShowDisMin = tonumber(arrTimeShowDis[1] or 0) or 0
	self._cfgVShowDisMax = tonumber(arrTimeShowDis[2] or 0) or 0

	-- local tempStrs = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["RadioRanCD"] or "")-- [[0.9;1.1]]
	-- self._cfgVSayCd = {
	-- 	min = tonumber(tempStrs[1] or 1) or 1,
	-- 	max = tonumber(tempStrs[2] or 1) or 1,
	-- }
	self._cfgVSayCd = {
		min = 1,
		max = 1,
	}

	----------------------------------------------------------------
	local tempBloodRetureMap = LxDataHelper.ParseIntKVList_Semicolon(GameTable.MainInstanceConfigRef["BloodReture"] or "")
	local bloodRetureList = {}
	for k,v in pairs(tempBloodRetureMap) do
		table.insert(bloodRetureList,{hp=k,rate=v})
	end
	table.sort(bloodRetureList,function (b1,b2) return b1.hp < b2.hp end)
	self._cfgVArrBloodReture = bloodRetureList

	self._cfgVShakeCD = GameTable.MainInstanceConfigRef["ShakeCd"]
	self._cfgVMissBlood = GameTable.MainInstanceConfigRef["MissBlood"]

	self._cfgMonCreateNum = GameTable.MainInstanceConfigRef["MonCreateNum"]
	self._cfgMonCreateCd = GameTable.MainInstanceConfigRef["MonCreateCd"]

	self._cfgMonHitByHand = GameTable.MainInstanceConfigRef["MonHitByHand"]
	self._cfgMonHitEffect = GameTable.MainInstanceConfigRef["MonHitEffect"]

	local arrHeroXY = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["HeroXY"] or "")-- [[0;200]]
	self._cfgHeroXY = Vector2((tonumber(arrHeroXY[1]) or 0) / 100 , (tonumber(arrHeroXY[2]) or 0) / 100)

	self._cfgMonHitNum = GameTable.MainInstanceConfigRef["MonHitNum"]

	local heroTalkIntervals = string.split(GameTable.MainInstanceConfigRef["heroTalkInterval"], ";") or {}
	self._cfgHeroTalkIntervalMin = (heroTalkIntervals[1] or 0) * 60
	self._cfgHeroTalkIntervalMax = (heroTalkIntervals[2] or 0) * 60

	local rewardShowStrList = LxDataHelper.ParseStringParam_Semicolon(GameTable.MainInstanceConfigRef["rewardShow"]) or {}
	local rewardShowList = {}
	for k, v in ipairs(rewardShowStrList) do
		local arr = string.split(v, "=")
		local limitArr = string.split(arr[3], ":")
		local data = {
			name = arr[1],
			time = checknumber(arr[2]),
			min = checknumber(limitArr[1]),
			max = checknumber(limitArr[2])
		}
		table.insert(rewardShowList, data)
	end
	self._rewardShowList = rewardShowList

end

