---初始化所有控制器的
function LFightIdleManager:InitCtrl()
	self._nextShakeTime = 0
	self._nextBloodReturningTime = 0

	self._effCtrl:InitMask(self._mapTrans, false)

	self._hudCtrl:InitHud()
	self._dropCtrl:InitDropPool(self._dropPoolTrans)
	if self._isNewMoveType then
		self._dropCtrl:InitAutoDropData(self._rewardShowList)
	end

	local idleMapRef = self._curMapIdleRef
	self._pathCtrl:InitPath(idleMapRef.links,idleMapRef.boards)

	local areaCtrl = self._areaCtrl
	local boardsRoot = self:GetBoardRootTrans()
	areaCtrl:InitArea(idleMapRef,self._moveDistance * 0.01,self._moveType,boardsRoot)
	areaCtrl:ShowAllArea()

	self._hurtCalc:InitData(self._cfgVHeroHitMonMap,self._cfgVMonAttPerMap,self._cfgVMissBlood)

	-----------------------------------------------------------------
	self._enemyMaker:InitMaker(self._monList,self._cfgVBoardNum, self._cfgVMonWeightList , self._cfgVMonQualityMaxList, self._cfgVMonWeightAddList,self._monAttrRefId)

	-----------------------------------------------------------------
	local monAttackSpeed = GameTable.MainInstanceConfigRef["MonAttackSpeed"]
	local heroAttackSpeed = GameTable.MainInstanceConfigRef["HeroAttackSpeed"]
	local moveSpeed = GameTable.MainInstanceConfigRef["HeroMoveSpeed"]
	local heroSizeOnHook = GameTable.MainInstanceConfigRef["HeroSizeOnHook"] or 1
	local jumpCD = GameTable.MainInstanceConfigRef["JumpCD"]
	-- local heroAttSpeedUp = GameTable.MainInstanceConfigRef["HeroAttSpeedUp"] or 1
	local heroAttSpeedUp = gModelInstance:GetHeroAttSpeedUp()
	local monPatrolSpeedRate =  GameTable.MainInstanceConfigRef["MonMoveSpeed1"] or 1
	self._objCtrl:InitHeroData(heroAttackSpeed,moveSpeed,heroSizeOnHook,self._cfgVHeroAttDisOnHookMap,jumpCD,heroAttSpeedUp)
	self._objCtrl:InitMonData(monAttackSpeed,self._cfgVMonAttDisOnHookTbl,self._cfgVMonMoveAreaSize,self._cfgVMonStayTimeLimit,monPatrolSpeedRate,self._cfgVMonSizeOnHook)
	self._objCtrl:InitGodSkillData(self._cfgMonHitEffect, self._cfgMonHitByHand)
	self._objCtrl:InitSpinePool(self._spinePoolTrans)

	local moveStart = GameTable.MainInstanceConfigRef["heroMoveStart"] or 1
	local moveUp = GameTable.MainInstanceConfigRef["heroMoveUp"] or 1
	local heroDistance = GameTable.MainInstanceConfigRef["heroDistance"] or 1
	local heroNum = GameTable.MainInstanceConfigRef["heroNum"] or 1
	local heroScaleRate = GameTable.MainInstanceConfigRef["heroScale"] or 1
	local monScaleRate = GameTable.MainInstanceConfigRef["monScale"] or 1
	self._objCtrl:InitHeroNewData(moveStart, moveUp, heroDistance, heroNum, heroScaleRate, monScaleRate)

	-----------------------------------------------------------------
	--飘字伤害分隔
	local floatHurtSplitList = self._cfgVFloatHurtSplitList
	local floatHurtWaveMin = self._cfgVFloatHurtWaveMin
	local floatHurtWaveMax = self._cfgVFloatHurtWaveMax
	local floatHurtY = GameTable.MainInstanceConfigRef["FloatHurtY"] -- 15
	local floatHurtTime = GameTable.MainInstanceConfigRef["FloatHurtTime"] -- 0.05
	local hurtXMin = self._cfgVHurtXMin
	local hurtXMax = self._cfgVHurtXMax
	self._hurtCalc:InitFloatData(floatHurtSplitList,floatHurtWaveMin,floatHurtWaveMax,floatHurtY,floatHurtTime,hurtXMin,hurtXMax)

	-----------------------------------------------------------------
	-- local instanceTalkTime2 = GameTable.MainInstanceConfigRef["InstanceTalkTime2"] or 3
	local instanceTalkTime2 = 3
	local talkTimeMin = self._cfgVTalkTimeMin
	local talkTimeMax = self._cfgVTalkTimeMax

	-- local monTalkTime2 = GameTable.MainInstanceConfigRef["MonsterTalkTime2"] or 3
	local monTalkTime2 = 3
	self._bubbleCtrl:InitBubble(talkTimeMin,talkTimeMax,instanceTalkTime2, self._cfgVMonTalkTimeMin, self._cfgVMonTalkTimeMax, monTalkTime2)

	self._bubbleCtrl:SetHeroTalkBubble((GameTable.MainInstanceConfigRef["heroTalkTime"] or 0) * 60, self._cfgHeroTalkIntervalMin, self._cfgHeroTalkIntervalMax)

	-----------------------------------------------------------------
	local timeShowStay = tonumber(GameTable.MainInstanceConfigRef["TimeShowStay"] or 0) or 0
	local showDisMin = self._cfgVShowDisMin
	local showDisMax = self._cfgVShowDisMax
	local dropFlyNum = GameTable.MainInstanceConfigRef["DropFlyNum"]
	local dropByHand = GameTable.MainInstanceConfigRef["DropByHand"] or 1
	self._dropCtrl:InitDropData(timeShowStay,showDisMin,showDisMax,dropFlyNum,dropByHand)

	-----------------------------------------------------------------
	self._logCtrl:InitData(self._cfgVSayCd)
end

