---摄像机适配
function LFightIdleManager:OnCameraAdapt()
	self:SetCameraAdapt()
	if self._btIdleController then
		self:SetCameraPos(self._btIdleController:GetCameraPos())
	end
	--	self:PrepareCameraSetting()
end

function LFightIdleManager:SetCameraAdapt()
	if not self._btIdleController then return end
	local scene = gLGameScene:GetCurrentScene()
	local offset = scene:GetCameraAdaptOffset()
	self._cameraOffset = Vector3(0,offset,0)
end

function LFightIdleManager:SetCameraPos(pos)
	local posOffset = self._cameraOffset or Vector3(0,0,0)
	self._btIdleController:SetCameraPos(pos + posOffset)
end

function LFightIdleManager:SetFollowCamera(dpTrans)
	local range = self._cfgVCameraFollowRange
	if self._isNewMoveType then
		self._btIdleController.followSmooth = 30
		range = 0
	end
	self._btIdleController:StartFollow(dpTrans,self._cfgVCameraFollowOffset, range)
end

function LFightIdleManager:StopMoveCamera()
	if self._btIdleController then self._btIdleController:StopMove() end
end

function LFightIdleManager:GetCameraViewBounds()
	local UScreen = UnityEngine.Screen
	local sceneCamera = gLGameScene:GetCurrentSceneCamera()
	local point1 = sceneCamera:ScreenToWorldPoint(Vector3(0,0,0))
	local point2 = sceneCamera:ScreenToWorldPoint(Vector3(UScreen.width,UScreen.height,0))
	return point1.x,point2.x,point1.y,point2.y
end
------------------------------------------------------------------
function LFightIdleManager:StartBtIdle(mapTrans,chapterId,battleNode,mapName,monList,monAttrRefId, missionList)
	self:Clear()

	self:ParseIdleConfig()

	self._mapTrans = mapTrans
	self._chapterId = chapterId
	self._battleNode = battleNode

	local mapRefId = mapName.."Ref"
	--mapRefId = "MapBtIdle1001Ref"
	local idleMapRef = GameTable[mapRefId]

	self._curMapIdleRef = idleMapRef
	self._moveType = idleMapRef.moveType
	self._moveDistance = idleMapRef.moveDistance
	self._monList = monList
	self._monAttrRefId = monAttrRefId
	self._missionList = missionList
	self._isNewMoveType = idleMapRef.isNewMoveType == 1

	self:InitRootNode()
	self:InitCSBtController()

	--挂机改为多屏刷怪
	--self:PrepareMissionData()

	self:PrepareCameraSetting(true)

	self._isDelayInitOk = false

	self:StartInitTimer()
end

function LFightIdleManager:OnDelayInit()
	self._isDelayInitOk = true

	self:CreateNewCtrl()
	self:InitCtrl()

	self:InitEvent()
	self:InitTouchEvent()

	if not self._isNewMoveType then
		self:PrepareBtIdleSetting()

		--挂机改为多屏刷怪
		--self:MakeMissions()

		--self:RefreshNextEnemyInBoards(true)

		self:OnResetMySelfHero()
		self._objCtrl:PreloadGodSkill()
	else
		self:FirstGetFormationData()
	end

	self:StartIdleRun()
end

function LFightIdleManager:PrepareMissionData()
	local battleNode = self._battleNode
	local missionList = self._missionList
	local currentMission = nil
	for k,v in ipairs(missionList) do
		-- local missionData = self:GetMissionData(v.monsterShow)
		local missionData = nil
		if v.refId == battleNode then
			currentMission = missionData
			break
		end
	end

	self._initPos = nil
	self._ownerBoardList = nil
	self._currentMissionId = nil
	self._currentMissionBoardRefId = nil

	if not currentMission then
		return
	end
	local pos = currentMission.pos:Clone()
	local offsetPos = self._cfgHeroXY or Vector2(0, 0)
	pos.x = pos.x - offsetPos.x
	pos.y = pos.y - offsetPos.y

	self._initPos = pos
	local ownerBoardList = currentMission.ownerBoardList
	self._ownerBoardList = ownerBoardList
	self._currentMissionId = currentMission.refId
	self._currentMissionBoardRefId = currentMission.board
end

function LFightIdleManager:PrepareCameraSetting(bSetLeaderPos)
	self._btIdleController:ResetAll()
	local pixelPos = self._curMapIdleRef.initPos
	local initCameraPos = self:ConvertPixelPosToUnitPos(pixelPos)

	local initPos = self._initPos or initCameraPos:Clone()
	if self._moveType == LFightIdleConst.MAP_MOVE_TYPE_HORIZONTAL then
		self._lastMaxPos = initPos.x
		initCameraPos.x = initPos.x
	else
		self._lastMaxPos = initPos.y
		initCameraPos.y = initPos.y
	end
	self:SetCameraPos(initCameraPos)
	self._btIdleController:DoInit()

	self._initLeaderPos = self._curMapIdleRef.birthPos

	if(bSetLeaderPos) then
		self._currentLeaderPos = initCameraPos
	end
end

function LFightIdleManager:GetInitLeaderPos()
	if self._initLeaderPos then
		return self._initLeaderPos
	end
	return Vector3.zero
end


---准备挂机数据,初始化设定,初始怪物
function LFightIdleManager:PrepareBtIdleSetting()
	self._nextShakeTime = 0
	self._nextBloodReturningTime = 0

	local areaCtrl = self:GetAreaCtrl()
	local enemyMaker = self._enemyMaker
	enemyMaker:MakeNextAreaEnemy(areaCtrl:GetAreaData(1),1)
	enemyMaker:MakeNextAreaEnemy(areaCtrl:GetAreaData(2),2)
	enemyMaker:MakeNextAreaEnemy(areaCtrl:GetAreaData(3),3)

	self._lastAreaIndex = 1
	self._lastEnemyArea = 3
	self._curAreaIndex = 1


	self._enemyMaker:CheckCacheLoadArea(self._lastEnemyArea)
end

---初始化节点
function LFightIdleManager:InitRootNode()
	local mapTrans = self._mapTrans

	local layerRoot = CS.FindTrans(mapTrans,"LayerRoot")
	self._layerRootTrans = layerRoot

	self._boardRootTrans = CS.FindTrans(layerRoot,"LayerBoard")

	local layerTrans = nil

	layerTrans = CS.FindTrans(layerRoot,"LayerObject")
	if not layerTrans then
		layerTrans = CS.NewObject("LayerObject",layerRoot)
	end
	self._objRootTrans = layerTrans

	layerTrans = CS.FindTrans(layerRoot,"LayerEffect")
	if not layerTrans then
		layerTrans = CS.NewObject("LayerEffect",layerRoot)
	end
	self._effectRootTrans = layerTrans

	layerTrans = CS.FindTrans(layerRoot,"LayerPool")
	if not layerTrans then
		layerTrans = CS.NewObject("LayerPool",layerRoot)
	end

	local dropPoolTrans = CS.FindTrans(layerTrans, "DropPool")
	if not dropPoolTrans then
		dropPoolTrans = CS.NewObject("DropPool", layerTrans)
	end
	self._dropPoolTrans = dropPoolTrans

	self._spinePoolTrans = layerTrans
end

---初始化控制器
function LFightIdleManager:InitCSBtController()
	self._btIdleController = self._layerRootTrans:GetComponent(typeMapBTIdleController)
end

---初始化事件
function LFightIdleManager:InitEvent()
	--self:EventRecv(EventNames.ON_HOOK_HERO_CHANGE,function ()
	--	self:OnResetMySelfHero()
	--end)
	if not self._isNewMoveType then
		self:EventRecv(EventNames.ON_SPACE_PLAY_FIGURE_CHANGE,function ()
			self:OnResetMySelfHero()
		end)

		self:EventRecv(EventNames.HERO_ATTR_REQUEST_DONE,function (...)
			self:OnUpdateMySelfHeroAttr(...)
		end)
	else
		self:EventRecv(EventNames.ON_SET_FORMATION_RESP, function(dictFormationType)
			if dictFormationType[LCombatTypeConst.COMBAT_SHOW_BATTLE] then
				local formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_SHOW_BATTLE)
				if not formation then
					return
				end
				self:OnResetFormationHero(formation)
			elseif dictFormationType[LCombatTypeConst.COMBAT_MAIN] then
				local formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_SHOW_BATTLE)
				if formation then
					return
				end
				formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_MAIN)
				if not formation then
					return
				end
				self:OnResetFormationHero(formation)
			end
		end)
		self:EventRecv(EventNames.ON_GET_FORMATION_RET, function(formationType)
			if formationType == LCombatTypeConst.COMBAT_MAIN then
				local formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_SHOW_BATTLE)
				if not formation then
					formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_MAIN)
				end
				if not formation then
					return
				end
				self:OnResetFormationHero(formation)
			elseif formationType == LCombatTypeConst.COMBAT_SHOW_BATTLE then
				local formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_SHOW_BATTLE)
				if not formation then
					return
				end
				self:OnResetFormationHero(formation)
			end
		end)
	end
end

