function LFightIdleManager:GetWndEffectRootTrans()
	if not self._wndEffectRootTrans then
		local uiFightRoot = LGameUI.GetUIFight()
		local hudRootTrans = CS.FindTrans(uiFightRoot,"UIEffect")
		if not hudRootTrans then
			hudRootTrans = CS.NewObject("UIEffect", uiFightRoot)
			local obj = hudRootTrans.gameObject
			obj:AddComponent(typeof(UnityEngine.RectTransform))
			---加了RectTransform后，之前的transform控件会被移除，。 需要重新赋值
			hudRootTrans = obj.transform
		end
		self._wndEffectRootTrans = hudRootTrans
	end
	return self._wndEffectRootTrans
end

