---初始化据点
function LFightIdleManager:MakeMissions()
	local battleNode = gModelInstance and gModelInstance:GetRawBattleNode() or -1
	if battleNode == -1 then return end

	local missionList = self._missionList
	local currentMissionId = self._currentMissionId
	for k,v in ipairs(missionList) do
		-- local missionData = self:GetMissionData(v.monsterShow)
		local missionData = nil
		--只显示当前要打的据点
		if missionData and missionData.refId == currentMissionId then
			local obj = self._objCtrl:MakeMissionObject(v, missionData, missionData.refId > currentMissionId)
			if obj then
				local pos = obj:GetPosition()
				local minPos,maxPos = obj:GetPathData()
				self._dropCtrl:DoMissionDrop(Vector3(pos.x,pos.y,0),minPos,maxPos)
			end
		end
	end
end

