---初始化新横板挂机的阵容英雄
function LFightIdleManager:FirstGetFormationData()
	local formation = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_SHOW_BATTLE)
	if not formation then
		gModelFormation:OnGetFormationReq(LCombatTypeConst.COMBAT_SHOW_BATTLE)
		return
	end
	self:OnResetFormationHero(formation)
end

---@param formationData StructFormationData
function LFightIdleManager:OnResetFormationHero(formationData)
	local grids = formationData.grids
	if not grids then return end
	table.sort(grids, function(a, b) return a.grid < b.grid  end)
	local result = {}
	for k,v in ipairs(grids) do
		local heroServerData = gModelHero:GetHeroById(v.id)
		if heroServerData then
			table.insert(result, heroServerData)
		end
	end
	self._objCtrl:CreateFormationHeroObjs(result)

	local leader = self._objCtrl:GetLeaderObject()
	if leader then
		self._currentLeaderPos = leader:GetPosition()
		self._objCtrl:CheckFormationHeroFollow(self._currentLeaderPos)
	end
end
---初始化英雄数据
function LFightIdleManager:OnResetMySelfHero()
	local tblList = {}
	--local figureData = gModelPlayer:GetPlayFigureData(ModelPlayer.PLAY_IMAGE_HANG)
	--local heroId = figureData and figureData.heroId
	local figure = gModelPlayer:GetPlayerFigure()
	local adventureRef = gModelPlayer:GetRoleAdventureImage(figure)
	local heroEffectId = adventureRef and adventureRef.hero or nil
	local heroEffectRef = gModelHero:GetShowEffectById(heroEffectId)
	local isExist = false
	local heroId = nil
	if heroEffectRef then
		local heroRefId = heroEffectRef.heroType
		local heroLv = 0
		local heroList = gModelHero:GetHeroList()
		local skin
		local isSame = false
		for k,v in pairs(heroList) do
			if heroRefId == v:GetRefId() then
				skin = v:GetSkin()
				if skin and skin > 0 then
					local tHeroEffectRef = gModelHero:GetShowEffectById(skin)
					if tHeroEffectRef then
						if tHeroEffectRef.originRefId == heroRefId then
							isSame = true
						else
							isSame = skin == heroEffectId
						end
					end
				else
					isSame = true
				end
				if isSame then
					if not heroId then
						heroId = v:GetId()
						heroLv = v:GetLv()
					else
						local lv = v:GetLv()
						if lv > heroLv then
							heroId = v:GetId()
							heroLv = lv
						end
					end
				end
			end
		end
		local heroData = heroId and gModelHero:GetHeroById(heroId) or nil
		if heroData then
			isExist = true
		end
	end

	if isExist then
		table.insert(tblList,heroId)
	else
		--冒险英雄丢失
		--gModelPlayer:AutoUpHangHero()
	end


	self._objCtrl:ResetMySelfHero(tblList ,self._curAreaIndex,self._currentLeaderPos, heroEffectId)

	local leader = self._objCtrl:GetLeaderObject()
	if leader then
		self._currentLeaderPos = leader:GetPosition()
	end
end

