function LFightIdleManager:OnChallengeMain()
	if not self._isNewMoveType then
		--不是新挂机模式，直接执行挑战
		gModelInstance:GotoChallenge()
		return
	end
	if not self._isDelayInitOk or not self._objCtrl then
		gModelInstance:GotoChallenge()
		return
	end
	--self._objCtrl:DoAttackMission()
	local missionRef = GameTable.MainInstanceMissionRef[self._battleNode]
	if missionRef then
		self._objCtrl:GotoBoss(missionRef.monsterShow, self._initLeaderPos)
	end
end

function LFightIdleManager:OnChallengeUIShow(bShow)
	-- 弹出UI，先关闭主角的AI
	if self._objCtrl then
		local leaderObj = self._objCtrl:GetLeaderObject()
		if leaderObj then
			leaderObj:GetAI():SetCanChangeAction(not bShow)
		end
	end

	-- 关闭遮罩显示
	if not bShow then
		self:ShowCameraMask(false)
	end
end

function LFightIdleManager:ShowCameraMask(bShow)
	if self._effCtrl then
		self._effCtrl:ShowMask(bShow)
	end
	
	if not bShow then
		if self._objCtrl then
			self._objCtrl:ClearMaskObj()
		end
	end
end
