function LFightIdleManager:NotifyObjDead(obj)
	local objType = obj:GetObjType()
	if objType == LFightIdleConst.OBJ_MON then
		self._enemyMaker:OnEnemyDead(obj)
		--屏蔽击杀怪物界面显示
		--gModelInstance:AddClientKillMon(1)
		gModelInstance:SetLifeMon(self._enemyMaker:GetLifeCnt())

		local pos = obj:GetPosition()
		local minPos,maxPos = obj:GetPathData()
		self._dropCtrl:DoDropLittle(Vector3(pos.x,pos.y,0),minPos,maxPos,obj:GetQuality())

		local topPos = obj:GetTopNodePos() or Vector3(0, 0, 0)
		FireEvent(EventNames.BTIDLE_MONSTER_DEAD,Vector3(topPos.x,topPos.y,0))
	end
end

