function LFightIdleManager:CheckDelLimitDisMonster()
	local pos = self._currentLeaderPos
	local areaX,areaY = self:GetOneAreaOffset()
	local nowMax = 0
	local limitDis = 0
	if self._moveType == LFightIdleConst.MAP_MOVE_TYPE_HORIZONTAL then
		nowMax = pos.x
		limitDis = areaX * 4
	else
		nowMax = pos.y
		limitDis = areaY * 4
	end

	self._objCtrl:CheckDelLimitDisMonster(self._moveType,nowMax,limitDis)
end

function LFightIdleManager:CheckHeroForward()
	local leader = self._objCtrl:GetLeaderObject()
	if not leader then return end
	local pos = leader:GetPosition()
	if pos == self._currentLeaderPos then return end
	self._currentLeaderPos = pos
	local nowMax = 0
	if self._moveType == LFightIdleConst.MAP_MOVE_TYPE_HORIZONTAL then
		nowMax = pos.x
	else
		nowMax = pos.y
	end

	local areaCtrl = self._areaCtrl
	local areaIndex = areaCtrl:CalcAreaIndexByPos(nowMax)

	self._curAreaIndex = areaIndex

	local tailStartIndex = areaCtrl:GetTailStartIndex()
	local headStartIndex = areaCtrl:GetHeadStartIndex()

	if nowMax > self._lastMaxPos then
		self._lastMaxPos = nowMax
		local lastIdx = self._lastAreaIndex
		if areaIndex > lastIdx then
			self._lastAreaIndex = areaIndex

			if not self._isNewMoveType then
				self:RefreshAreaEnemy(areaIndex + 2)
			end

			if tailStartIndex > 0 and areaIndex >= tailStartIndex then
				self:DoMapCircle()
			end
		end
	end
end

function LFightIdleManager:RefreshNextAreaEnemy()
	--print("refresh next area enemy", self._lastEnemyArea)
	self:RefreshAreaEnemy(self._lastEnemyArea + 1)
	--print("refresh next area enemy end", self._lastEnemyArea)
end

function LFightIdleManager:RefreshAreaEnemy(maxArea)
	local areaCtrl = self._areaCtrl
	local tailStartIndex = areaCtrl:GetTailStartIndex()
	local headStartIndex = areaCtrl:GetHeadStartIndex()

	local lastEnemyArea = self._lastEnemyArea

	local bNeedReset = false
	if lastEnemyArea < tailStartIndex then
		bNeedReset = true
	end

	local enemyAreaIndex = lastEnemyArea + 1
	for k = enemyAreaIndex, maxArea, 1 do
		enemyAreaIndex = k
		if enemyAreaIndex >= headStartIndex and headStartIndex > 0 then
			break
		end
		--重置刷怪标记
		if tailStartIndex > 0 and enemyAreaIndex >= tailStartIndex and bNeedReset then
			bNeedReset = false
			self._enemyMaker:ResetBoardEnemyMadeMap()
		end
		local areaData = areaCtrl:GetAreaData(enemyAreaIndex)
		self._lastEnemyArea = enemyAreaIndex
		self._enemyMaker:MakeNextAreaEnemy(areaData,enemyAreaIndex)
	end

	if lastEnemyArea ~= self._lastEnemyArea then
		self._enemyMaker:CheckCacheLoadArea(self._lastEnemyArea)
	end
end

-------------------------------------------------------------------
function LFightIdleManager:RefreshNextEnemyInBoards(bInit)
	local monCount = self._cfgMonCreateNum
	local bNewMonRefId = true
	if bInit then
		local recordCount = gModelInstance:GetLifeMon()
		if recordCount > 0 then
			monCount = recordCount
			bNewMonRefId = false
		end
	end

	local monRefId = bNewMonRefId and gModelInstance:GenerateNewShowMonRefId() or gModelInstance:GetShowMonRefId()


	self._enemyMaker:MakeEnemyInBoards(self._ownerBoardList or {}, monCount, monRefId)

	local lifeCnt = self._enemyMaker:GetLifeCnt()
	gModelInstance:SetLifeMon(lifeCnt)

end

function LFightIdleManager:CheckRefreshNextEnemy(time)
	local lifeCnt = self._enemyMaker:GetLifeCnt()
	if lifeCnt > 0 then return end
	if not self._bSendSearchMon then
		self._bSendSearchMon = true
		self._refreshMonTime = self:GetTime() + self._cfgMonCreateCd
		FireEvent(EventNames.BTIDLE_SEARCH_MON, true)

		if CS.IsWebGL() then
			--LResRelease.WebglRelease()
			LxResUtil.RunUnusedAssetUnload()
		end
		return
	end
	if time >= self._refreshMonTime then
		self:RefreshNextEnemyInBoards(false)
		self._bSendSearchMon = false
		FireEvent(EventNames.BTIDLE_SEARCH_MON, false)
	end
end
-----------------------------------------------------------------

function LFightIdleManager:DoMapCircle()
	local objCtrl = self._objCtrl
	local dropCtrl = self._dropCtrl
	local effCtrl = self._effCtrl
	local areaCtrl = self._areaCtrl

	local circlePos = areaCtrl:GetCircleAreaOffset()
	local offset = circlePos:Clone()
	offset.x = -offset.x
	offset.y = -offset.y

	if self._isNewMoveType then
		objCtrl:CircleAreaForNew(offset)
	else
		objCtrl:CircleArea(offset)
	end
	effCtrl:CircleArea(offset)
	dropCtrl:CircleArea(offset)

	local cameraPos = self._btIdleController:GetCameraPos()
	self._btIdleController:CircleCamera(cameraPos + offset)

	local areaCount = areaCtrl:GetAreaCount()
	--最后刷的怪物等于前面刷的怪物
	local areaIndex = self._lastEnemyArea - areaCount
	self._lastEnemyArea = areaIndex
	self._lastAreaIndex = self._lastAreaIndex - areaCount
	self._lastMaxPos = 0
	local leader = self._objCtrl:GetLeaderObject()
	if not leader then return end
	local pos = leader:GetPosition()
	self._currentLeaderPos = pos

end

function LFightIdleManager:DoShake(time,intensityX,intensityY)
	local curTime = self:GetTime()
	if self._nextShakeTime < curTime then
		self._nextShakeTime = curTime + self._cfgVShakeCD
		GF.ShakeMainScene(time,intensityX,intensityY)
	end
end

function LFightIdleManager:DoRecoverLife()
	self._objCtrl:CheckRecoverAllHeroLife(self._cfgVArrBloodReture,self._cfgVMissBlood)
end

-----------------------------------------------------------------
function LFightIdleManager:StopInitTimer()
	if not self._initTimer  then return end
	LxTimer.DelayTimeStop(self._initTimer)
	self._initTimer  = nil
end

function LFightIdleManager:StartInitTimer()
	self:StopInitTimer()
	self._initTimer = LxTimer.DelayTimeCall(function()
		self:OnDelayInit()
	end,0.5,false)
end

function LFightIdleManager:StartIdleRun()
	self:StopIdleRun()
	self._loopTimer = LxTimer.LoopTimeCall(function()
		self:OnIdleRun()
	end,0,false,-1)
end

function LFightIdleManager:StopIdleRun()
	if not self._loopTimer  then return end
	LxTimer.LoopTimeStop(self._loopTimer)
	self._loopTimer  = nil
end

function LFightIdleManager:OnIdleRun()
	local time = self:GetTime()

	self._enemyMaker:OnRun(time)
	self._objCtrl:OnRun(time)
	self._effCtrl:OnRun(time)
	self._dropCtrl:OnRun(time)
	self._hudCtrl:OnRun(time)
	self._bubbleCtrl:OnRun(time)
	self._logCtrl:OnRun(time)

	self:CheckHeroForward()
	if not self._isNewMoveType then

		self:CheckDelLimitDisMonster()
		--改成多屏弹跳
		--self:CheckRefreshNextEnemy(time)

		self:DoRecoverLife()
	else
		self._objCtrl:CheckFormationHeroFollow(self._currentLeaderPos)
	end

	local runEndFunc = self._runEndEventFunc
	self._runEndEventFunc = nil
	if runEndFunc then
		runEndFunc()
	end
end

function LFightIdleManager:AddRunEndEventFunc(func)
	if self._runEndEventFunc then return end
	self._runEndEventFunc = func
end

------------------------------------------------------------------------------
--- touch event
------------------------------------------------------------------------------
function LFightIdleManager:InitTouchEvent()
	local startFunc = function (screenPos)
		self._curClickMissionObj = false
		local bPointObject = YXTouchManager.IsPointerOverGameObject()
		local bStartPick = true
		if bPointObject then
			local touchObject = YXTouchManager.EventSystemRaycastGameObject(screenPos)
			if touchObject then
				local gameObject =  touchObject
				if gameObject.name == "Collider" then
					local parentTrans = gameObject.transform.parent
					local layerName
					if parentTrans then
						parentTrans = parentTrans.parent
					end
					if parentTrans then
						layerName = parentTrans.name
					end
					if layerName ~= "LayerObject" then
						bStartPick = false
					end
				else
					bStartPick = false
				end
			end
		end
		if bStartPick then
			local pos = gLGameScene:GetCurrentSceneCamera():ScreenToWorldPoint(screenPos)
			self._objCtrl:OnTouchStart(pos)

			self._dropCtrl:EnablePick(true)
			self._dropCtrl:SetPickPos(pos)
		end
	end

	local moveFunc = function (screenPos)
		local pos = gLGameScene:GetCurrentSceneCamera():ScreenToWorldPoint(screenPos)
		self._objCtrl:OnTouchMove(pos)

		if self._dropCtrl:IsEnablePick() then
			self._dropCtrl:SetPickPos(pos)
		end
	end

	local endFunc = function (screenPos)
		local pos = gLGameScene:GetCurrentSceneCamera():ScreenToWorldPoint(screenPos)
		
		local bKillMoster = self._objCtrl:OnTouchEnd(pos)
		local bSelBoss = self._curClickMissionObj		
		local bPickDrop = self._dropCtrl:IsClickPickDrop()
		
		self:OnThinkingDataRecord(bSelBoss, bPickDrop, bKillMoster)
		
		self._dropCtrl:EnablePick(false)
	end

	local cancelFunc = function (screenPos)
		self._objCtrl:OnTouchCancel()
		self._dropCtrl:EnablePick(false)
	end

	self:RegisterTouchEvent(LGameTouch.TOUCH_BT_IDLE, startFunc, moveFunc, endFunc, cancelFunc)
end
-----------------------------------------------------------------
-- 数数科技点击事件记录
function LFightIdleManager:OnThinkingDataRecord(bSelBoss, bPickDrop, bKillMoster)
	local bClickUI = YXTouchManager.IsPointerOverGameObject()
	
	if bSelBoss then
		gLxTKData:OnBtIdleClick(102)
	else
		if bPickDrop then
			gLxTKData:OnBtIdleClick(100)
			-- LxUiHelper.PlayAudioSoundName(30)
			if bKillMoster then
				gLxTKData:OnBtIdleClick(101)
			end
		else
			if bKillMoster then
				gLxTKData:OnBtIdleClick(101)
			elseif not bClickUI then
				--gLxTKData:OnBtIdleClick(103)
			end
		end
	end
end

